const raw = $input.item.json.text;
const cleaned = raw.replace(/```json\n?/g, '').replace(/```/g, '').trim();
try {
  const parsed = JSON.parse(cleaned);
  return { json: parsed };
} catch(e) {
  return { json: { 
    full_name: '', company: '', department: '',
    title: '', email: '', phone: '',
    address: '', website: '',
    notes: 'Parse error: ' + raw
  }};
}

